3	import (
4		"github.com/go-git/go-git/v6/plumbing"
5	)
6	
7	// RelayTargetPolicy captures only the target-side facts that affect planner
8	// relay eligibility decisions.
9	type RelayTargetPolicy struct {
10		CapabilitiesKnown bool
11		NoThin            bool
12	}
13	
14	// SupportsReplicateRelay checks target-side capabilities required by
15	// replication mode before looking at planned ref actions.
16	//
17	// Replicate tolerates targets that advertise "no-thin" because our
18	// upload-pack client (gitproto.FetchPack) never requests the "thin-pack"
19	// capability, so the source never emits a thin pack. The relayed pack is
20	// always self-contained and safe to push to a no-thin receive-pack.
21	// If gitproto.FetchPack ever begins requesting thin-pack, this check must
22	// gain a matching fallback (omit the request, or explicitly advertise
23	// NoThin on the source request) when target.NoThin is set.
24	func SupportsReplicateRelay(target RelayTargetPolicy) (bool, string) {
25		if !target.CapabilitiesKnown {
26			return false, "replicate-missing-target-capabilities"
27		}
28		if target.NoThin {
29			return true, "replicate-target-capable-no-thin"
30		}
31		return true, "replicate-target-capable"
32	}
33	
34	// CanBootstrapRelay checks whether all desired target refs are absent on the target,
35	// making a bootstrap relay possible.
36	func CanBootstrapRelay(
37		force, prune bool,
38		desired map[plumbing.ReferenceName]DesiredRef,
39		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
40	) (bool, string) {
41		if force || prune {
42			return false, "bootstrap-disabled-by-force-or-prune"
43		}
44		if len(desired) == 0 {
45			return false, "bootstrap-no-managed-refs"
46		}
47		for targetRef := range desired {
48			if !targetRefs[targetRef].IsZero() {
49				return false, "bootstrap-target-ref-exists"
50			}
51		}
52		return true, "empty-target-managed-refs"
53	}
54	
55	// reasonIncrementalEligible is returned when all plans satisfy the incremental
56	// relay eligibility rules — branch FF updates, branch creates, or tag creates.
57	const reasonIncrementalEligible = "fast-forward-branch-or-tag-create"
58	
59	// CanIncrementalRelay checks whether all plans are eligible for the incremental
60	// relay fast-path. Eligible plan shapes:
61	//   - Branch fast-forward update (TargetHash is parent of SourceHash).
62	//   - Branch create (target has no such ref yet). The relay still passes
63	//     all target refs as haves, so the source pack covers only objects
64	//     target doesn't already have via some existing ref. The receive-pack
65	//     accepts the create command because any pruned objects are reachable
66	//     from those existing refs.
67	//   - New tag create.
68	//
69	// Incremental tolerates targets that advertise "no-thin" for the same reason
70	// as replicate (see SupportsReplicateRelay): gitproto.FetchPack never requests
71	// the "thin-pack" capability, so the relayed pack is always self-contained.
72	// If gitproto.FetchPack ever begins requesting thin-pack, this function must
73	// gain a matching fallback when target.NoThin is set.
74	func CanIncrementalRelay(force, prune, dryRun bool, plans []BranchPlan, target RelayTargetPolicy) (bool, string) {
75		if force || prune || dryRun {
76			return false, "incremental-disabled-by-force-prune-or-dry-run"
77		}
78		if len(plans) == 0 {
79			return false, "incremental-no-plans"
80		}
81		if !target.CapabilitiesKnown {
82			return false, "incremental-missing-target-capabilities"
83		}
84	
85		for _, plan := range plans {
86			switch plan.Kind {
87			case RefKindBranch:
88				if !plan.SourceRef.IsBranch() || !plan.TargetRef.IsBranch() {
89					return false, "incremental-non-branch-mapping"
90				}
91				switch plan.Action {
92				case ActionUpdate:
93					if plan.TargetHash.IsZero() {
94						return false, "incremental-branch-target-missing"
95					}
96				case ActionCreate:
97					if !plan.TargetHash.IsZero() {
98						return false, "incremental-branch-create-target-not-empty"
99					}
100				case ActionDelete, ActionSkip, ActionBlock, ActionWarn:
101					return false, "incremental-branch-action-not-update-or-create"
102				}
103			case RefKindTag:
104				if !plan.SourceRef.IsTag() || !plan.TargetRef.IsTag() {
105					return false, "incremental-non-tag-mapping"
106				}
107				if plan.Action != ActionCreate {
108					return false, "incremental-tag-action-not-create"
109				}
110			case RefKindOther:
111				return false, "incremental-unsupported-ref-kind"
112			}
113		}
114		return true, reasonIncrementalEligible
115	}
