117	// CanFullTagCreateRelay checks whether all plans are tag creates, eligible for
118	// a full-pack tag relay.
119	func CanFullTagCreateRelay(plans []BranchPlan) (bool, string) {
120		if len(plans) == 0 {
121			return false, "incremental-no-plans"
122		}
123		for _, plan := range plans {
124			if plan.Kind != RefKindTag {
125				return false, "incremental-tag-relay-non-tag-plan"
126			}
127			if !plan.SourceRef.IsTag() || !plan.TargetRef.IsTag() {
128				return false, "incremental-tag-relay-non-tag-mapping"
129			}
130			if plan.Action != ActionCreate {
131				return false, "incremental-tag-relay-tag-action-not-create"
132			}
133		}
134		return true, "tag-create-full-pack"
135	}
136	
137	// RelayFallbackReason returns the reason why relay was not used.
138	func RelayFallbackReason(force, prune, dryRun bool, plans []BranchPlan, target RelayTargetPolicy) string {
139		if ok, reason := CanIncrementalRelay(force, prune, dryRun, plans, target); ok {
140			return reason
141		}
142		_, reason := CanFullTagCreateRelay(plans)
143		return reason
144	}
145	
146	// CanReplicateRelay checks whether replication mode can execute as a relay-only
147	// overwrite sync against the target.
148	func CanReplicateRelay(plans []BranchPlan) (bool, string) {
149		for _, plan := range plans {
150			switch plan.Kind {
151			case RefKindBranch:
152				if !plan.SourceRef.IsBranch() || !plan.TargetRef.IsBranch() {
153					return false, "replicate-non-branch-mapping"
154				}
155				if plan.Action != ActionCreate && plan.Action != ActionUpdate {
156					return false, "replicate-branch-action-not-create-or-update"
157				}
158			case RefKindTag:
159				if !plan.SourceRef.IsTag() || !plan.TargetRef.IsTag() {
160					return false, "replicate-non-tag-mapping"
161				}
162				if plan.Action != ActionCreate && plan.Action != ActionUpdate {
163					return false, "replicate-tag-action-not-create-or-update"
164				}
165			case RefKindOther:
166				// Replicate's contract is overwrite, so the FF concern that keeps
167				// other-kind refs out of the sync incremental relay doesn't apply
168				// here — a notes/pull ref update is just another ref-update relay.
169				if RefKindFromName(plan.SourceRef) != RefKindOther || RefKindFromName(plan.TargetRef) != RefKindOther {
170					return false, "replicate-non-other-mapping"
171				}
172				if plan.Action != ActionCreate && plan.Action != ActionUpdate {
173					return false, "replicate-other-action-not-create-or-update"
174				}
175			default:
176				return false, "replicate-unsupported-ref-kind"
177			}
178		}
179		return true, "replicate-overwrite-relay"
