1	package gitproto
2	
3	import (
4		"bytes"
5		"context"
6		"errors"
7		"fmt"
8		"io"
9		"os"
10		"strings"
11	
12		"github.com/go-git/go-git/v6/plumbing"
13		"github.com/go-git/go-git/v6/plumbing/format/packfile"
14		"github.com/go-git/go-git/v6/plumbing/protocol/capability"
15		"github.com/go-git/go-git/v6/plumbing/protocol/packp"
16		"github.com/go-git/go-git/v6/plumbing/protocol/packp/sideband"
17		"github.com/go-git/go-git/v6/plumbing/storer"
18		"github.com/go-git/go-git/v6/plumbing/transport"
19	)
20	
21	// PushCommand represents a single ref update command.
22	type PushCommand struct {
23		Name   plumbing.ReferenceName
24		Old    plumbing.Hash
25		New    plumbing.Hash
26		Delete bool
27	}
28	
29	// Pusher wraps target-side receive-pack state behind a smaller execution API.
30	// When OnRejection is non-nil, per-ref ng statuses invoke it instead of erroring;
31	// pack-level unpack failure remains fatal.
32	//
33	// Returned by NewPusher as a pointer so callers can attach OnRejection after
34	// construction without worrying about whether downstream strategies have
35	// already captured a value copy.
36	type Pusher struct {
37		Conn        Conn
38		Adv         *packp.AdvRefs
39		Verbose     bool
40		OnRejection func(refName plumbing.ReferenceName, status string)
41	}
42	
43	// NewPusher builds a target-side push executor.
44	func NewPusher(conn Conn, adv *packp.AdvRefs, verbose bool) *Pusher {
45		return &Pusher{Conn: conn, Adv: adv, Verbose: verbose}
46	}
47	
48	// PushPack streams a pack to the target.
49	func (p *Pusher) PushPack(ctx context.Context, commands []PushCommand, pack io.ReadCloser) error {
50		return PushPack(ctx, p.Conn, p.Adv, commands, pack, p.Verbose, p.OnRejection)
51	}
52	
53	// PushCommands sends ref-only updates without a pack.
54	func (p *Pusher) PushCommands(ctx context.Context, commands []PushCommand) error {
55		return PushCommands(ctx, p.Conn, p.Adv, commands, p.Verbose, p.OnRejection)
56	}
57	
58	// PushObjects encodes and pushes locally materialized objects.
59	func (p *Pusher) PushObjects(ctx context.Context, commands []PushCommand, store storer.Storer, hashes []plumbing.Hash) error {
60		return PushObjects(ctx, p.Conn, p.Adv, commands, store, hashes, p.Verbose, p.OnRejection)
61	}
62	
63	// buildUpdateRequest builds the receive-pack update request.
64	func buildUpdateRequest(
65		adv *packp.AdvRefs,
66		commands []PushCommand,
67		verbose bool,
68	) (*packp.UpdateRequests, bool, bool, error) {
69		req := &packp.UpdateRequests{}
70		if sb := PreferredSideband(&adv.Capabilities); sb != "" {
71			req.Capabilities.Set(sb)
72		}
73		if adv.Capabilities.Supports(capability.ReportStatus) {
74			req.Capabilities.Set(capability.ReportStatus)
75		}
76	
77		hasDelete := false
78		hasUpdates := false
79		for _, cmd := range commands {
80			c := &packp.Command{Name: cmd.Name, Old: cmd.Old}
81			if cmd.Delete {
82				c.New = plumbing.ZeroHash
83				hasDelete = true
84			} else {
85				c.New = cmd.New
86				hasUpdates = true
87			}
88			req.Commands = append(req.Commands, c)
89		}
90	
91		if hasDelete {
92			if !adv.Capabilities.Supports(capability.DeleteRefs) {
93				return nil, false, false, errors.New("target does not support delete-refs")
94			}
95			req.Capabilities.Set(capability.DeleteRefs)
96		}
97	
98		_ = verbose // progress handling is server-side in HTTP mode
99		return req, hasDelete, hasUpdates, nil
100	}
101	
102	// leaseFailureMarkers are receive-pack ng reason substrings that indicate the
103	// captured target tip didn't match what was on the server at push time. Match
104	// is case-insensitive. CommandStatusErr.Status is a free-form string in go-git,
105	// so substring matching is the only option absent upstream sentinels.
106	var leaseFailureMarkers = []string{
107		"stale info",
108		"fetch first",
109		"non-fast-forward",
110		"does not match",
111	}
112	
113	// IsLeaseFailure reports whether a receive-pack ng reason indicates the
114	// captured target tip no longer matched at push time. Callers that downgrade
115	// per-ref rejections to warnings (BestEffort) must still treat these as fatal
116	// to preserve --force-with-lease semantics.
117	func IsLeaseFailure(status string) bool {
118		lowered := strings.ToLower(status)
119		for _, marker := range leaseFailureMarkers {
120			if strings.Contains(lowered, marker) {
121				return true
122			}
123		}
124		return false
125	}
126	
127	// annotateLeaseFailure wraps a lease-failure CommandStatusErr with a retry/
128	// override hint. Other receive-pack errors pass through unchanged.
129	func annotateLeaseFailure(err error) error {
130		var cs *packp.CommandStatusErr
131		if !errors.As(err, &cs) {
132			return err
133		}
134		if !IsLeaseFailure(cs.Status) {
135			return err
136		}
137		return fmt.Errorf("%w (target ref %s moved or differs from session start; rerun, or use --force-blind to overwrite)", err, cs.ReferenceName)
138	}
139	
140	// sendReceivePack encodes and POSTs a receive-pack request, then decodes the report.
141	func sendReceivePack(
142		ctx context.Context,
143		conn Conn,
144		req *packp.UpdateRequests,
145		packData io.Reader,
146		verbose bool,
147		onRejection func(plumbing.ReferenceName, string),
148	) error {
149		var header bytes.Buffer
150		if err := req.Encode(&header); err != nil {
151			return fmt.Errorf("encode update-request: %w", err)
152		}
153		body := io.Reader(bytes.NewReader(header.Bytes()))
154		if packData != nil {
155			body = io.MultiReader(body, packData)
156		}
157		reader, err := PostRPCStreamBody(ctx, conn, transport.ReceivePackService, body, false, "receive-pack push")
158		if err != nil {
159			return fmt.Errorf("target receive-pack: %w", err)
160		}
161		defer reader.Close()
162	
163		// Unwrap sideband if negotiated; stream server-side progress to stderr
164		// when verbose so long-running pushes show "Resolving deltas ..." etc.
165		var respReader io.Reader = reader
166		switch {
167		case req.Capabilities.Supports(capability.Sideband64k):
168			dem := sideband.NewDemuxer(sideband.Sideband64k, reader)
169			dem.Progress = progressSink(verbose, "target: ", conn.ProgressWriter())
170			respReader = dem
171		case req.Capabilities.Supports(capability.Sideband):
172			dem := sideband.NewDemuxer(sideband.Sideband, reader)
173			dem.Progress = progressSink(verbose, "target: ", conn.ProgressWriter())
174			respReader = dem
175		}
176	
177		if req.Capabilities.Supports(capability.ReportStatus) {
178			report := &packp.ReportStatus{}
179			if err := report.Decode(respReader); err != nil {
180				return fmt.Errorf("decode report-status: %w", err)
181			}
182			if onRejection == nil {
183				if err := report.Error(); err != nil {
184					return fmt.Errorf("report-status: %w", annotateLeaseFailure(err))
185				}
186				return nil
187			}
188			if report.UnpackStatus != "" && report.UnpackStatus != "ok" {
189				return fmt.Errorf("report-status: unpack error: %s", report.UnpackStatus)
190			}
191			for _, cs := range report.CommandStatuses {
192				if cs.Status == "" || cs.Status == "ok" {
193					continue
194				}
195				onRejection(cs.ReferenceName, cs.Status)
196			}
197		}
198		return nil
199	}
200	
201	// PushObjects pushes locally-materialized objects to the target.
202	func PushObjects(
203		ctx context.Context,
204		conn Conn,
205		adv *packp.AdvRefs,
206		commands []PushCommand,
207		store storer.Storer,
208		hashes []plumbing.Hash,
209		verbose bool,
210		onRejection func(plumbing.ReferenceName, string),
211	) error {
212		req, _, hasUpdates, err := buildUpdateRequest(adv, commands, verbose)
213		if err != nil {
214			return err
215		}
216		if !hasUpdates {
217			return sendReceivePack(ctx, conn, req, nil, verbose, onRejection)
218		}
219	
220		useRefDeltas := !adv.Capabilities.Supports(capability.OFSDelta)
221		pr, pw := io.Pipe()
222		done := make(chan error, 1)
223	
224		go func() {
225			enc := packfile.NewEncoder(pw, store, useRefDeltas)
226			if _, err := enc.Encode(hashes, 10); err != nil {
227				done <- pw.CloseWithError(fmt.Errorf("encode packfile: %w", err))
228				return
229			}
230			done <- pw.Close()
231		}()
232	
233		err = sendReceivePack(ctx, conn, req, pr, verbose, onRejection)
234		_ = pr.Close()
235		encodeErr := <-done
236		if err != nil {
237			return err
238		}
239		return encodeErr
240	}
241	
242	// PushPack pushes a pack stream (relay) to the target.
243	func PushPack(
244		ctx context.Context,
245		conn Conn,
246		adv *packp.AdvRefs,
247		commands []PushCommand,
248		pack io.ReadCloser,
249		verbose bool,
250		onRejection func(plumbing.ReferenceName, string),
251	) error {
252		for _, cmd := range commands {
253			if cmd.Delete {
254				_ = pack.Close()
255				return errors.New("pack push only supports create and update actions")
256			}
257		}
258	
259		req, _, _, err := buildUpdateRequest(adv, commands, verbose)
260		if err != nil {
261			_ = pack.Close()
262			return err
263		}
264	
265		err = sendReceivePack(ctx, conn, req, pack, verbose, onRejection)
266		closeErr := pack.Close()
267		if err != nil {
268			return err
269		}
270		if closeErr != nil {
271			return fmt.Errorf("close pack: %w", closeErr)
272		}
273		return nil
274	}
275	
276	// PushCommands sends ref update commands without a pack (for ref-only changes).
277	func PushCommands(
278		ctx context.Context,
279		conn Conn,
280		adv *packp.AdvRefs,
281		commands []PushCommand,
282		verbose bool,
283		onRejection func(plumbing.ReferenceName, string),
284	) error {
285		req, _, _, err := buildUpdateRequest(adv, commands, verbose)
286		if err != nil {
287			return err
288		}
289		return sendReceivePack(ctx, conn, req, nil, verbose, onRejection)
290	}
291	
292	func progressWriter(verbose bool, dest io.Writer) io.Writer {
293		if !verbose {
294			return nil
295		}
296		if dest == nil {
297			dest = os.Stderr
298		}
299		return dest
300	}
301	
302	// progressSink returns a line-prefixing io.Writer suitable for
303	// sideband.Demuxer.Progress. When verbose is false it returns nil so the
304	// demuxer discards progress frames without allocating. Passing a non-nil
305	// dest routes the prefixed lines through that writer instead of os.Stderr,
306	// which lets a live progress reporter coordinate output.
307	func progressSink(verbose bool, prefix string, dest io.Writer) io.Writer {
308		if !verbose {
309			return nil
310		}
311		if dest == nil {
312			dest = os.Stderr
313		}
314		return &prefixedLineWriter{w: dest, prefix: prefix, atLineStart: true}
315	}
316	
317	// prefixedLineWriter prepends a fixed prefix to each line of input written
318	// to the wrapped writer. Git sideband progress arrives as chunks that may
319	// contain '\n' between full lines or '\r' for in-place updates ("Resolving
320	// deltas:  12%\r"); both are treated as line terminators so the next chunk
321	// gets a fresh prefix.
322	type prefixedLineWriter struct {
323		w           io.Writer
324		prefix      string
325		atLineStart bool
326	}
327	
328	func (p *prefixedLineWriter) Write(b []byte) (int, error) {
329		consumed := 0
330		for len(b) > 0 {
331			if p.atLineStart {
332				if _, err := io.WriteString(p.w, p.prefix); err != nil {
333					return consumed, fmt.Errorf("write prefix: %w", err)
334				}
335				p.atLineStart = false
336			}
337			i := bytes.IndexAny(b, "\r\n")
338			var chunk []byte
339			if i < 0 {
340				chunk = b
341			} else {
342				chunk = b[:i+1]
343				p.atLineStart = true
344			}
345			n, err := p.w.Write(chunk)
346			consumed += n
347			if err != nil {
348				return consumed, fmt.Errorf("write chunk: %w", err)
349			}
350			b = b[len(chunk):]
351		}
352		return consumed, nil
353	}
