// TestPushPackSendsContentLengthAndBuffersBody asserts the receive-pack POST
// is sent with an explicit Content-Length (not chunked), and that the pack
// reader is drained before the HTTP request reaches the server. Both are
// consequences of spooling unknown-length bodies to a temp file in
// HTTPConn.PostRPCStreamBody — the workaround for servers (Cloudflare's
// git frontend among them) that close the connection on chunked uploads.
func TestPushPackSendsContentLengthAndBuffersBody(t *testing.T) {
	type observation struct {
		transferEncoding []string
		contentLength    int64
		bodyLen          int64
	}
	observed := make(chan observation, 1)
	release := make(chan struct{})

	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		n, err := io.Copy(io.Discard, r.Body)
		if err != nil {
			t.Logf("drain request body: %v", err)
		}
		_ = r.Body.Close()
		observed <- observation{
			transferEncoding: r.TransferEncoding,
			contentLength:    r.ContentLength,
			bodyLen:          n,
		}
		w.WriteHeader(http.StatusOK)
	}))
	defer srv.Close()

	conn := connForServer(t, srv)
	adv := &packp.AdvRefs{}

	pack := &gatedReadCloser{
		first:   []byte("PACK"),
		second:  strings.Repeat("x", 1024),
		release: release,
	}

	done := make(chan error, 1)
	go func() {
		done <- PushPack(context.Background(), conn, adv, []PushCommand{{
			Name: "refs/heads/main",
			New:  plumbing.NewHash("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa"),
		}}, pack, false, nil)
	}()

	// The spool reads the entire pack into a temp file before the POST
	// is dispatched, so releasing the gate must happen first for the
	// request to ever reach the server.
	select {
	case obs := <-observed:
		t.Fatalf("server saw request before pack was released: %+v", obs)
	case <-time.After(100 * time.Millisecond):
	}
	close(release)

	var obs observation
	select {
	case obs = <-observed:
	case <-time.After(2 * time.Second):
		t.Fatal("server did not receive request after pack released")
	}

	if len(obs.transferEncoding) != 0 {
		t.Errorf("Transfer-Encoding = %v, want empty (no chunked)", obs.transferEncoding)
	}
	if obs.contentLength <= 0 {
		t.Errorf("Content-Length = %d, want > 0", obs.contentLength)
	}
	if obs.bodyLen != obs.contentLength {
		t.Errorf("body length %d != Content-Length %d", obs.bodyLen, obs.contentLength)
	}

	select {
	case err := <-done:
		if err != nil {
			t.Fatalf("PushPack returned error: %v", err)
		}
	case <-time.After(2 * time.Second):
		t.Fatal("PushPack did not complete after releasing pack")
	}
}

