63	// buildUpdateRequest builds the receive-pack update request.
64	func buildUpdateRequest(
65		adv *packp.AdvRefs,
66		commands []PushCommand,
67		verbose bool,
68	) (*packp.UpdateRequests, bool, bool, error) {
69		req := &packp.UpdateRequests{}
70		if sb := PreferredSideband(&adv.Capabilities); sb != "" {
71			req.Capabilities.Set(sb)
72		}
73		if adv.Capabilities.Supports(capability.ReportStatus) {
74			req.Capabilities.Set(capability.ReportStatus)
75		}
76	
77		hasDelete := false
78		hasUpdates := false
79		for _, cmd := range commands {
80			c := &packp.Command{Name: cmd.Name, Old: cmd.Old}
81			if cmd.Delete {
82				c.New = plumbing.ZeroHash
83				hasDelete = true
84			} else {
85				c.New = cmd.New
86				hasUpdates = true
87			}
88			req.Commands = append(req.Commands, c)
89		}
