102	// leaseFailureMarkers are receive-pack ng reason substrings that indicate the
103	// captured target tip didn't match what was on the server at push time. Match
104	// is case-insensitive. CommandStatusErr.Status is a free-form string in go-git,
105	// so substring matching is the only option absent upstream sentinels.
106	var leaseFailureMarkers = []string{
107		"stale info",
108		"fetch first",
109		"non-fast-forward",
110		"does not match",
111	}
112	
113	// IsLeaseFailure reports whether a receive-pack ng reason indicates the
114	// captured target tip no longer matched at push time. Callers that downgrade
115	// per-ref rejections to warnings (BestEffort) must still treat these as fatal
116	// to preserve --force-with-lease semantics.
117	func IsLeaseFailure(status string) bool {
118		lowered := strings.ToLower(status)
119		for _, marker := range leaseFailureMarkers {
120			if strings.Contains(lowered, marker) {
121				return true
122			}
123		}
124		return false
