// PrecomputedSelector returns a single-use ObjectSelector whose
// ObjectsToPack returns the supplied objects on the first call and an
// error on every subsequent call. Intended for use with
// WithObjectSelector after running DeltaSelector.ObjectsToPack ahead
// of time.
//
// Single-use because Encode mutates the supplied *ObjectToPack values
// during the write phase (sets Offset, marks WantWrite, may swap to
// the non-delta representation on cycle recovery). Reusing the same
// slice in a second Encode call would silently produce a pack with
// missing object bodies — the encoder would treat each object as
// already written and skip it. Callers needing another pack must
// rerun DeltaSelector.ObjectsToPack and build a fresh
// PrecomputedSelector.
func PrecomputedSelector(objects []*ObjectToPack) ObjectSelector {
	return &precomputedSelector{objects: objects}
}

// ErrPrecomputedSelectorReused is returned by PrecomputedSelector's
// ObjectsToPack on any call after the first. See PrecomputedSelector.
var ErrPrecomputedSelectorReused = errors.New("packfile: PrecomputedSelector reused (the supplied ObjectToPacks are mutated by Encode; build a fresh selector per pack)")

type precomputedSelector struct {
	objects []*ObjectToPack
	used    atomic.Bool
}

func (p *precomputedSelector) ObjectsToPack(
	_ []plumbing.Hash,
	_ uint,
) ([]*ObjectToPack, error) {
	if !p.used.CompareAndSwap(false, true) {
		return nil, ErrPrecomputedSelectorReused
	}
	return p.objects, nil
}

