func (s *EncoderSuite) TestWithObjectSelectorNilPreservesDefault() {
	o := newObject(plumbing.BlobObject, []byte("x"))
	_, err := s.store.SetEncodedObject(o)
	s.NoError(err)

	enc := NewEncoder(s.buf, s.store, false, WithObjectSelector(nil))
	_, err = enc.Encode([]plumbing.Hash{o.Hash()}, 10)
	s.NoError(err)
}

// TestPrecomputedSelectorIsSingleUse asserts that a PrecomputedSelector
// returns ErrPrecomputedSelectorReused on its second ObjectsToPack
// call. Encode mutates the supplied ObjectToPacks during the write
// phase (sets Offset, marks WantWrite), so silently returning the same
// slice on a second use would produce a broken pack with missing
// object bodies. Failing loudly is safer.
func (s *EncoderSuite) TestPrecomputedSelectorIsSingleUse() {
	o := newObject(plumbing.BlobObject, []byte("hello"))
	_, err := s.store.SetEncodedObject(o)
	s.NoError(err)

	sel := NewDeltaSelector(s.store)
	objects, err := sel.ObjectsToPack([]plumbing.Hash{o.Hash()}, 10)
	s.NoError(err)

	pre := PrecomputedSelector(objects)

	enc1 := NewEncoder(bytes.NewBuffer(nil), s.store, false, WithObjectSelector(pre))
	_, err = enc1.Encode([]plumbing.Hash{o.Hash()}, 10)
	s.NoError(err)

	enc2 := NewEncoder(bytes.NewBuffer(nil), s.store, false, WithObjectSelector(pre))
	_, err = enc2.Encode([]plumbing.Hash{o.Hash()}, 10)
	s.ErrorIs(err, ErrPrecomputedSelectorReused)
}

