// ObjectSelector decides which objects go into a pack and in what
// order, including any delta relationships. The default selector is
// *DeltaSelector; callers can supply a different one via
// WithObjectSelector — for example a passthrough wrapping objects
// that were produced ahead of time, so Encoder.Encode can stream
// output without an internal selection delay.
type ObjectSelector interface {
	ObjectsToPack(hashes []plumbing.Hash, packWindow uint) ([]*ObjectToPack, error)
}

// Encoder gets the data from the storage and write it into the writer in PACK
// format
type Encoder struct {
	selector       *DeltaSelector
	objectSelector ObjectSelector
	w              *offsetWriter
	zw             sync.ZlibWriter
	hasher         hash.Hash

	useRefDeltas bool
}

// EncoderOption configures an Encoder at construction time.
type EncoderOption func(*Encoder)

// WithObjectSelector overrides the ObjectSelector used by Encode to
// produce the object list. The default is the encoder's own
// *DeltaSelector, which runs delta selection synchronously when
// Encode is called.
//
// Supplying a precomputed selector — e.g. PrecomputedSelector wrapping
// the result of a prior DeltaSelector.ObjectsToPack call — lets Encode
// skip the selection step and start writing pack bytes immediately.
// This is useful when the encoder's writer is something like an HTTP
// request body where a multi-second mid-stream stall trips server
// timeouts. The encoder still uses its own internal *DeltaSelector
// for recovery operations during the write phase (e.g. when a
// concurrent repack invalidates a chosen delta base), so the storer
// passed to NewEncoder must remain valid.
func WithObjectSelector(s ObjectSelector) EncoderOption {
	return func(e *Encoder) {
		if s != nil {
			e.objectSelector = s
		}
	}
}

// PrecomputedSelector returns a single-use ObjectSelector whose
// ObjectsToPack returns the supplied objects on the first call and an
// error on every subsequent call. Intended for use with
// WithObjectSelector after running DeltaSelector.ObjectsToPack ahead
// of time.
//
// Single-use because Encode mutates the supplied *ObjectToPack values
// during the write phase (sets Offset, marks WantWrite, may swap to
// the non-delta representation on cycle recovery). Reusing the same
// slice in a second Encode call would silently produce a pack with
// missing object bodies — the encoder would treat each object as
// already written and skip it. Callers needing another pack must
// rerun DeltaSelector.ObjectsToPack and build a fresh
// PrecomputedSelector.
func PrecomputedSelector(objects []*ObjectToPack) ObjectSelector {
	return &precomputedSelector{objects: objects}
}

// ErrPrecomputedSelectorReused is returned by PrecomputedSelector's
// ObjectsToPack on any call after the first. See PrecomputedSelector.
var ErrPrecomputedSelectorReused = errors.New("packfile: PrecomputedSelector reused (the supplied ObjectToPacks are mutated by Encode; build a fresh selector per pack)")

type precomputedSelector struct {
	objects []*ObjectToPack
	used    atomic.Bool
}

func (p *precomputedSelector) ObjectsToPack(
	_ []plumbing.Hash,
	_ uint,
) ([]*ObjectToPack, error) {
	if !p.used.CompareAndSwap(false, true) {
		return nil, ErrPrecomputedSelectorReused
	}
	return p.objects, nil
}

// NewEncoder creates a new packfile encoder using a specific Writer and
// EncodedObjectStorer. By default deltas used to generate the packfile will be
// OFSDeltaObject. To use Reference deltas, set useRefDeltas to true.
//
// Optional EncoderOptions configure encoder behavior; see
// WithObjectSelector for the main use case (precomputed selection for
// streaming output).
func NewEncoder(w io.Writer, s storer.EncodedObjectStorer, useRefDeltas bool, opts ...EncoderOption) *Encoder {
	var of cfgformat.ObjectFormat
	if c, ok := s.(config.ConfigStorer); ok {
		cfg, err := c.Config()
		if err == nil {
			of = cfg.Extensions.ObjectFormat
		}
	}

	var h hash.Hash
	if of == cfgformat.SHA256 {
		h = hash.New(crypto.SHA256)
	} else {
		h = hash.New(crypto.SHA1)
	}

	mw := io.MultiWriter(w, h)
	ow := newOffsetWriter(mw)
	zw := sync.GetZlibWriter(mw)
	sel := NewDeltaSelector(s)
	e := &Encoder{
		selector:       sel,
		objectSelector: sel,
		w:              ow,
		zw:             zw,
		hasher:         h,
		useRefDeltas:   useRefDeltas,
	}
	for _, opt := range opts {
		opt(e)
	}
	return e
}

// Encode creates a packfile containing all the objects referenced in
// hashes and writes it to the writer in the Encoder.  `packWindow`
// specifies the size of the sliding window used to compare objects
// for delta compression; 0 turns off delta compression entirely.
//
// The object set is produced by the configured ObjectSelector (see
// WithObjectSelector). The encoder's internal *DeltaSelector is still
// used for recovery operations during the write phase regardless of
// the configured selector.
func (e *Encoder) Encode(
	hashes []plumbing.Hash,
	packWindow uint,
) (plumbing.Hash, error) {
	objects, err := e.objectSelector.ObjectsToPack(hashes, packWindow)
	if err != nil {
		return plumbing.ZeroHash, err
	}

	return e.encode(objects)
}

func (e *Encoder) encode(objects []*ObjectToPack) (plumbing.Hash, error) {
	if err := e.head(len(objects)); err != nil {
		return plumbing.ZeroHash, err
	}

	for _, o := range objects {
		if err := e.entry(o); err != nil {
			return plumbing.ZeroHash, err
		}
	}

	return e.footer()
}

