// TestWithObjectSelectorMatchesDefault asserts that running delta
// selection externally and feeding the result back via
// WithObjectSelector + PrecomputedSelector produces a byte-identical
// pack to the default Encode path. This is the contract callers
// streaming over slow transports rely on: pre-run selection, then
// stream the pack without an internal selection delay.
func (s *EncoderSuite) TestWithObjectSelectorMatchesDefault() {
	o1 := newObject(plumbing.BlobObject, []byte("hello"))
	o2 := newObject(plumbing.BlobObject, []byte("hello world"))
	o3 := newObject(plumbing.BlobObject, []byte("goodbye"))
	for _, o := range []plumbing.EncodedObject{o1, o2, o3} {
		_, err := s.store.SetEncodedObject(o)
		s.NoError(err)
	}
	hashes := []plumbing.Hash{o1.Hash(), o2.Hash(), o3.Hash()}

	// Default path: encoder runs selection internally.
	defaultBuf := bytes.NewBuffer(nil)
	defaultEnc := NewEncoder(defaultBuf, s.store, false)
	defaultHash, err := defaultEnc.Encode(hashes, 10)
	s.NoError(err)

	// Precomputed path: caller runs selection, then feeds objects
	// back via WithObjectSelector.
	sel := NewDeltaSelector(s.store)
	objects, err := sel.ObjectsToPack(hashes, 10)
	s.NoError(err)

	precomputedBuf := bytes.NewBuffer(nil)
	precomputedEnc := NewEncoder(precomputedBuf, s.store, false,
		WithObjectSelector(PrecomputedSelector(objects)))
	precomputedHash, err := precomputedEnc.Encode(hashes, 10)
	s.NoError(err)

	s.Equal(defaultHash, precomputedHash)
	s.Equal(defaultBuf.Bytes(), precomputedBuf.Bytes())
}

// TestWithObjectSelectorNilPreservesDefault asserts that
// WithObjectSelector(nil) is a no-op — the encoder keeps its own
// DeltaSelector. Defensive against callers building options lists
// conditionally.
func (s *EncoderSuite) TestWithObjectSelectorNilPreservesDefault() {
	o := newObject(plumbing.BlobObject, []byte("x"))
	_, err := s.store.SetEncodedObject(o)
	s.NoError(err)

	enc := NewEncoder(bytes.NewBuffer(nil), s.store, false, WithObjectSelector(nil))
	_, err = enc.Encode([]plumbing.Hash{o.Hash()}, 10)
	s.NoError(err)
}

// TestPrecomputedSelectorIsSingleUse asserts that a PrecomputedSelector
// returns ErrPrecomputedSelectorReused on its second ObjectsToPack
// call. Encode mutates the supplied ObjectToPacks during the write
// phase (sets Offset, marks WantWrite), so silently returning the same
// slice on a second use would produce a broken pack with missing
// object bodies. Failing loudly is safer.
func (s *EncoderSuite) TestPrecomputedSelectorIsSingleUse() {
	o := newObject(plumbing.BlobObject, []byte("hello"))
	_, err := s.store.SetEncodedObject(o)
	s.NoError(err)

	sel := NewDeltaSelector(s.store)
	objects, err := sel.ObjectsToPack([]plumbing.Hash{o.Hash()}, 10)
	s.NoError(err)

	pre := PrecomputedSelector(objects)

	enc1 := NewEncoder(bytes.NewBuffer(nil), s.store, false, WithObjectSelector(pre))
	_, err = enc1.Encode([]plumbing.Hash{o.Hash()}, 10)
	s.NoError(err)

	enc2 := NewEncoder(bytes.NewBuffer(nil), s.store, false, WithObjectSelector(pre))
	_, err = enc2.Encode([]plumbing.Hash{o.Hash()}, 10)
	s.ErrorIs(err, ErrPrecomputedSelectorReused)
}

