// AuthMethod authorizes outbound HTTP requests for a remote. It is satisfied
// by *transporthttp.BasicAuth and *transporthttp.TokenAuth, whose Authorizer
// methods replaced the AuthMethod interface that go-git removed in v6 alpha.2.
type AuthMethod interface {
	Authorizer(req *http.Request) error
}

// resettableAuth is the gitproto-side view of auth.Resettable. AuthMethods
// sourced from `git credential fill` implement Reset, which clears the
// cached credential via `git credential reject` so the next run looks
// up afresh. Duck-typed against auth.Resettable to avoid an import.
type resettableAuth interface {
	Reset(ctx context.Context) error
}

// maybeResetAuthOn401 invalidates the cached credential when the server
// returns 401. We only reset if AuthMethod is resettable (i.e. came
// from a credential helper); explicit flag/env tokens are static and
// can't be reset. Errors from Reset itself are surfaced to stderr but
// don't override the original 401 — the caller already has a clear
// auth-failed error to act on.
func maybeResetAuthOn401(ctx context.Context, auth AuthMethod, status int) {
	if status != http.StatusUnauthorized {
		return
	}
	r, ok := auth.(resettableAuth)
	if !ok {
		return
	}
