// resettableAuthSpy records Reset calls. Implements both AuthMethod
// and resettableAuth so it's a stand-in for the gitCredentialHelperAuth
// wrapper from the auth package.
type resettableAuthSpy struct {
	resets int
}

func (s *resettableAuthSpy) Authorizer(*http.Request) error { return nil }
func (s *resettableAuthSpy) Reset(context.Context) error {
	s.resets++
	return nil
}

func TestMaybeResetAuthOn401_ResetsResettableAuth(t *testing.T) {
	spy := &resettableAuthSpy{}
	maybeResetAuthOn401(t.Context(), spy, http.StatusUnauthorized)
	if spy.resets != 1 {
		t.Errorf("Reset called %d times, want 1", spy.resets)
	}
}

func TestMaybeResetAuthOn401_IgnoresOtherStatuses(t *testing.T) {
	for _, status := range []int{http.StatusOK, http.StatusForbidden, http.StatusInternalServerError} {
		spy := &resettableAuthSpy{}
		maybeResetAuthOn401(t.Context(), spy, status)
		if spy.resets != 0 {
			t.Errorf("status %d: Reset called %d times, want 0", status, spy.resets)
		}
	}
}

func TestMaybeResetAuthOn401_IgnoresNonResettableAuth(t *testing.T) {
	// Static *transporthttp.BasicAuth does not implement resettableAuth;
	// 401 against it should be a no-op (nothing to invalidate).
	auth := &transporthttp.BasicAuth{Username: "u", Password: "p"}
	maybeResetAuthOn401(t.Context(), auth, http.StatusUnauthorized) // must not panic
}

