		maybeResetAuthOn401(t.Context(), spy, status)
		if spy.resets != 0 {
			t.Errorf("status %d: Reset called %d times, want 0", status, spy.resets)
		}
	}
}

func TestMaybeResetAuthOn401_IgnoresNonResettableAuth(t *testing.T) {
	// Static *transporthttp.BasicAuth does not implement resettableAuth;
	// 401 against it should be a no-op (nothing to invalidate).
	auth := &transporthttp.BasicAuth{Username: "u", Password: "p"}
	maybeResetAuthOn401(t.Context(), auth, http.StatusUnauthorized) // must not panic
}

func TestMaybeResetAuthOn401_NilAuth(t *testing.T) {
	// Anonymous requests pass nil; must not panic.
	maybeResetAuthOn401(t.Context(), nil, http.StatusUnauthorized)
}

