75	func lookupGitCredential(ep *url.URL) (string, string, bool) {
76		input := credentialFillInput(ep)
77		if input == "" {
78			return "", "", false
79		}
80		output, err := GitCredentialFillCommand(context.Background(), input)
81		if err != nil {
82			return "", "", false
83		}
84		values := parseCredentialOutput(output)
85		password := values["password"]
86		if password == "" {
87			return "", "", false
88		}
89		username := values["username"]
90		if username == "" {
91			if ep.User != nil && ep.User.Username() != "" {
92				username = ep.User.Username()
93			} else {
94				username = defaultGitUsername
95			}
96		}
97		return username, password, true
98	}
99	
100	func credentialFillInput(ep *url.URL) string {
101		if ep == nil || ep.Hostname() == "" {
102			return ""
103		}
104		var b strings.Builder
105		fmt.Fprintf(&b, "protocol=%s\nhost=%s\n", ep.Scheme, ep.Hostname())
106		if path := strings.TrimPrefix(ep.Path, "/"); path != "" {
107			fmt.Fprintf(&b, "path=%s\n", path)
108		}
109		if ep.User != nil && ep.User.Username() != "" {
110			fmt.Fprintf(&b, "username=%s\n", ep.User.Username())
111		}
112		b.WriteString("\n")
113		return b.String()
114	}
115	
116	func parseCredentialOutput(output []byte) map[string]string {
117		values := map[string]string{}
118		for _, line := range strings.Split(string(output), "\n") {
119			line = strings.TrimSpace(line)
120			if line == "" {
121				continue
122			}
123			k, v, ok := strings.Cut(line, "=")
124			if ok {
125				values[k] = v
126			}
127		}
128		return values
129	}

